<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Bull Bitcoins DAC8-Fall — Zeitleiste und Schlüsselzahlen</text>
  <g font-family="sans-serif">
    <text x="20" y="65" fill="#a1a1aa" font-size="13">Zeitleiste</text>
    <rect x="20" y="80" width="200" height="50" rx="8" fill="#3f3f46"/>
    <text x="120" y="110" fill="#e4e4e7" font-size="13" font-weight="700" text-anchor="middle">1. Jan. 2026: DAC8 in Kraft</text>
    <text x="228" y="110" fill="#52525b" font-size="16" text-anchor="middle">→</text>
